package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostCreateProxy struct {
	automation.UnimplementedOnPostCreateServer
	client automation.OnPostCreateClient
}

func init() {
	proxyutil.Register(&automation.OnPostCreate_ServiceDesc, NewOnPostCreateProxy)
}
func NewOnPostCreateProxy(cc grpc.ClientConnInterface) automation.OnPostCreateServer {
	return &OnPostCreateProxy{client: automation.NewOnPostCreateClient(cc)}
}
func (p *OnPostCreateProxy) OnPostCreate(ctx context.Context, in *events.PostCreate) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostCreate, automation.HandlerResult](p.client.OnPostCreate)(ctx, in)
}
